import pytest
import requests

BASE_URL = "http://fhir-lite/fhir/R4"
ORG_A = "org-A"
EPOCH_ZERO = "1970-01-01T00:00:00Z"

@pytest.fixture
def officer_token_org_a():
    return <get_token_fixture>(role="privacy-officer", org=ORG_A)

def test_audit_events_from_epoch_zero_timestamp_boundary(officer_token_org_a):
    headers = {"Authorization": f"Bearer {officer_token_org_a}"}
    resp = requests.get(
        f"{BASE_URL}/AuditEvent",
        params={"organization": ORG_A, "_lastUpdated": f"ge{EPOCH_ZERO}"},
        headers=headers,
        timeout=10,
    )
    assert resp.status_code == 200, (
        f"Expected 200 for epoch-zero boundary, got {resp.status_code}: {resp.text}"
    )
    bundle = resp.json()
    assert bundle.get("resourceType") == "Bundle"
    for entry in bundle.get("entry", []):
        resource = entry.get("resource", {})
        agent_ref = resource["agent"][0]["who"].get("reference", "")
        assert ORG_A in agent_ref, f"Scoping violated at epoch boundary: {agent_ref}"

import pytest
import requests

BASE_URL = "http://fhir-lite/fhir/R4"
ORG_A = "org-A"
INT32_MAX = 2147483647

@pytest.fixture
def officer_token_org_a():
    return <get_token_fixture>(role="privacy-officer", org=ORG_A)

def test_audit_events_max_count_boundary_stays_org_scoped(officer_token_org_a):
    headers = {"Authorization": f"Bearer {officer_token_org_a}"}
    resp = requests.get(
        f"{BASE_URL}/AuditEvent",
        params={"organization": ORG_A, "_count": INT32_MAX},
        headers=headers,
        timeout=15,
    )
    assert resp.status_code != 500, "Server must not crash on INT32_MAX _count"
    assert resp.status_code in (200, 400), (
        f"Unexpected status {resp.status_code} for max _count boundary"
    )
    if resp.status_code == 200:
        bundle = resp.json()
        assert bundle.get("resourceType") == "Bundle"
        for entry in bundle.get("entry", []):
            resource = entry.get("resource", {})
            agent_ref = resource["agent"][0]["who"].get("reference", "")
            assert ORG_A in agent_ref, f"Cross-org leak at max _count: {agent_ref}"
